namespace sv_67ecc47cd736455c82e9ca112b9cf8eb.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_67ecc47cd736455c82e9ca112b9cf8eb.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<div class="container-fluid">
    <h1 class="mb-4">Product Catalog</h1>

    <div class="row">
        <!-- Sidebar Filters -->
        <div class="col-lg-3 col-md-4 mb-4">
            <div class="card">
                <div class="card-header fw-bold">Filters</div>
                <div class="card-body">
                    @if (categories is not null)
                    {
                        <h6>Category</h6>
                        <div class="mb-3">
                            @foreach (var category in categories)
                            {
                                <div class="form-check">
                                    <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                                           checked="@selectedCategories.Contains(category)"
                                           @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                                </div>
                            }
                        </div>
                    }

                    <h6>Price Range</h6>
                    <div class="row g-2 mb-3">
                        <div class="col-6">
                            <input type="number" class="form-control form-control-sm" placeholder="Min"
                                   value="@minPrice" @onchange="e => minPrice = ParseDecimal(e.Value)" />
                        </div>
                        <div class="col-6">
                            <input type="number" class="form-control form-control-sm" placeholder="Max"
                                   value="@maxPrice" @onchange="e => maxPrice = ParseDecimal(e.Value)" />
                        </div>
                    </div>

                    <div class="form-check mb-3">
                        <input class="form-check-input" type="checkbox" id="inStockOnly"
                               checked="@inStockOnly"
                               @onchange="e => inStockOnly = (bool)e.Value!" />
                        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                    </div>

                    <div class="d-grid gap-2">
                        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
                        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
                    </div>
                </div>
            </div>
        </div>

        <!-- Main Content -->
        <div class="col-lg-9 col-md-8">
            @if (isLoading)
            {
                <div class="d-flex justify-content-center align-items-center py-5">
                    <div class="spinner-border text-primary me-2" role="status"></div>
                    <span>Loading products...</span>
                </div>
            }
            else if (errorMessage is not null)
            {
                <div class="alert alert-danger" role="alert">
                    <strong>Error:</strong> @errorMessage
                </div>
            }
            else if (searchResult is null || searchResult.Items.Count == 0)
            {
                <div class="alert alert-info" role="alert">
                    No products found matching your criteria. Try adjusting your filters.
                </div>
            }
            else
            {
                <!-- Toolbar -->
                <div class="d-flex justify-content-between align-items-center mb-3">
                    <div>
                        <label class="me-2 fw-semibold" for="sortSelect">Sort by:</label>
                        <select id="sortSelect" class="form-select form-select-sm d-inline-block w-auto"
                                value="@sortBy" @onchange="OnSortChanged">
                            <option value="price_asc">Price: Low to High</option>
                            <option value="price_desc">Price: High to Low</option>
                            <option value="name_asc">Name: A-Z</option>
                            <option value="rating_desc">Rating: Highest</option>
                        </select>
                    </div>
                    <span class="text-muted">
                        Showing @ShowingStart–@ShowingEnd of @searchResult.TotalCount products
                    </span>
                </div>

                <!-- Product Grid -->
                <div class="row row-cols-1 row-cols-sm-2 row-cols-xl-3 g-4 mb-4">
                    @foreach (var product in searchResult.Items)
                    {
                        <div class="col">
                            <ProductCard Product="product"
                                         OnProductSelected="OnProductSelected"
                                         OnAddToCart="OnAddToCart" />
                        </div>
                    }
                </div>

                <!-- Pagination -->
                @if (TotalPages > 1)
                {
                    <nav aria-label="Product pagination">
                        <ul class="pagination justify-content-center">
                            <li class="page-item @(currentPage == 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(currentPage - 1)"
                                        disabled="@(currentPage == 1)">Previous</button>
                            </li>
                            @foreach (var p in GetPageNumbers())
                            {
                                <li class="page-item @(p == currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPage(p)">@p</button>
                                </li>
                            }
                            <li class="page-item @(currentPage == TotalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(currentPage + 1)"
                                        disabled="@(currentPage == TotalPages)">Next</button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        </div>
    </div>
</div>

@code {
    private List<string>? categories;
    private PagedResult<Product>? searchResult;

    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 9;

    private bool isLoading = true;
    private string? errorMessage;

    private int ShowingStart => searchResult is null ? 0 : (searchResult.Page - 1) * searchResult.PageSize + 1;
    private int ShowingEnd => searchResult is null ? 0 : Math.Min(searchResult.Page * searchResult.PageSize, searchResult.TotalCount);
    private int TotalPages => searchResult is null || searchResult.PageSize == 0
        ? 0
        : (int)Math.Ceiling((double)searchResult.TotalCount / searchResult.PageSize);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = LoadProducts();
            categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
            isLoading = false;
        }
    }

    private async Task LoadProducts()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            searchResult = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task OnSortChanged(ChangeEventArgs e)
    {
        sortBy = e.Value?.ToString() ?? "price_asc";
        currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > TotalPages) return;
        currentPage = page;
        await LoadProducts();
    }

    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 5;
        int start = Math.Max(1, currentPage - maxVisible / 2);
        int end = Math.Min(TotalPages, start + maxVisible - 1);
        start = Math.Max(1, end - maxVisible + 1);

        for (int i = start; i <= end; i++)
            yield return i;
    }

    private void OnProductSelected(Product product)
    {
        // Parent can handle navigation to detail page
    }

    private void OnAddToCart(Product product)
    {
        // Cart logic placeholder
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

@using sv_67ecc47cd736455c82e9ca112b9cf8eb.Services

<div class="card h-100 product-card" @onclick="HandleCardClick" role="button" style="cursor: pointer;">
    <div class="card-img-top bg-secondary bg-opacity-25 d-flex align-items-center justify-content-center"
         style="height: 180px;" role="img" aria-label="@Product.Name">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="card-text fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <div class="mb-2" title="@($"{Product.Rating:F1} out of 5")">
            @((MarkupString)GetStarRating(Product.Rating))
        </div>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <div class="mt-auto">
            <button class="btn btn-sm btn-success w-100"
                    disabled="@(!Product.InStock)"
                    @onclick="HandleAddToCart"
                    @onclick:stopPropagation="true">
                Add to Cart
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string GetStarRating(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}

